adminRouter.get('/wallet-balance/:accountId', async (req, res) => {
  const accountId = Number(req.params.accountId)
  const accounts = await listAccountsMySql()
  const masterAcc = accounts.find(a => a.id === accountId)
  
  if (!masterAcc) return res.status(404).json({ error: 'Cuenta maestra no encontrada' })

  const { clienteId, consignatarioId } = JSON.parse(masterAcc.extra_json ?? '{}')

  try {
     const balance = await fetchEfectivaleWalletBalance({
       masterAccount: {
         id: masterAcc.id,
         username: masterAcc.username,
         passwordEnc: masterAcc.password_enc,
         clienteId,
         consignatarioId,
       },
       debug: process.env.EFECTIVALE_DEBUG_HEADFUL === 'true'
     })
     res.json({ ok: true, balance })
  } catch (e: any) {
    res.status(500).json({ error: e.message })
  }
})

